For dynamic queries (optional filters, sorting, pagination), you must still keep the query structure controlled by your code and use parameters for all user-supplied values. Combine this with environment-aware configuration, rate limiting, and monitoring.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import { Pool, QueryConfig, QueryResult } from 'pg';
import helmet from 'helmet';
import rateLimit from 'express-rate-limit';

const app = express();
app.use(express.json());
app.use(helmet());

// Environment-specific DB config
const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  max: process.env.NODE_ENV === 'production' ? 20 : 5,
  idleTimeoutMillis: 30000,
});

// Basic rate limiting for admin search endpoint
const adminSearchLimiter = rateLimit({
  windowMs: 1 * 60 * 1000, // 1 minute
  max: 60, // 60 requests per minute
  standardHeaders: true,
  legacyHeaders: false,
});

interface UserSearchFilters {
  username?: string;
  email?: string;
  isActive?: boolean;
  sortBy?: 'username' | 'created_at';
  sortDir?: 'asc' | 'desc';
  limit: number;
  offset: number;
}

function parseAndValidateFilters(req: Request): UserSearchFilters {
  const {
    username,
    email,
    isActive,
    sortBy,
    sortDir,
    limit,
    offset,
  } = req.query;

  const filters: UserSearchFilters = {
    limit: 20,
    offset: 0,
  };

  if (username && typeof username === 'string') {
    if (!/^[a-zA-Z0-9_]{3,32}$/.test(username)) {
      throw new Error('Invalid username format');
    }
    filters.username = username;
  }

  if (email && typeof email === 'string') {
    if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)) {
      throw new Error('Invalid email format');
    }
    filters.email = email;
  }

  if (typeof isActive === 'string') {
    if (isActive !== 'true' && isActive !== 'false') {
      throw new Error('Invalid isActive value');
    }
    filters.isActive = isActive === 'true';
  }

  // Whitelist sortable columns and directions (never accept raw column names)
  if (sortBy === 'username' || sortBy === 'created_at') {
    filters.sortBy = sortBy;
  }

  if (sortDir === 'asc' || sortDir === 'desc') {
    filters.sortDir = sortDir;
  }

  const parsedLimit = Number(limit);
  if (!Number.isNaN(parsedLimit)) {
    filters.limit = Math.min(Math.max(parsedLimit, 1), 100);
  }

  const parsedOffset = Number(offset);
  if (!Number.isNaN(parsedOffset) && parsedOffset >= 0) {
    filters.offset = parsedOffset;
  }

  return filters;
}

function buildUserSearchQuery(filters: UserSearchFilters): QueryConfig {
  const conditions: string[] = [];
  const params: any[] = [];

  if (filters.username) {
    params.push(`%${filters.username}%`);
    conditions.push(`username ILIKE $${params.length}`);
  }

  if (filters.email) {
    params.push(`%${filters.email}%`);
    conditions.push(`email ILIKE $${params.length}`);
  }

  if (typeof filters.isActive === 'boolean') {
    params.push(filters.isActive);
    conditions.push(`is_active = $${params.length}`);
  }

  let sql = 'SELECT id, username, email, is_active, created_at FROM users';

  if (conditions.length > 0) {
    sql += ' WHERE ' + conditions.join(' AND ');
  }

  // Safe ORDER BY using only whitelisted values
  if (filters.sortBy) {
    const direction = filters.sortDir ?? 'asc';
    sql += ` ORDER BY ${filters.sortBy} ${direction.toUpperCase()}`;
  } else {
    sql += ' ORDER BY created_at DESC';
  }

  params.push(filters.limit);
  sql += ` LIMIT $${params.length}`;

  params.push(filters.offset);
  sql += ` OFFSET $${params.length}`;

  return { text: sql, values: params };
}

// Simple audit logger (could be sent to SIEM in real deployments)
function auditLog(message: string, details?: Record<string, unknown>): void {
  const entry = {
    level: 'INFO',
    ts: new Date().toISOString(),
    msg: message,
    ...details,
  };
  console.log(JSON.stringify(entry));
}

app.get('/admin/users', adminSearchLimiter, async (req: Request, res: Response) => {
  try {
    const filters = parseAndValidateFilters(req);
    const query = buildUserSearchQuery(filters);

    // Audit log (excluding sensitive fields)
    auditLog('Admin user search', {
      ip: req.ip,
      filters: {
        username: filters.username ? '[REDACTED]' : undefined,
        email: filters.email ? '[REDACTED]' : undefined,
        isActive: filters.isActive,
        sortBy: filters.sortBy,
        sortDir: filters.sortDir,
        limit: filters.limit,
        offset: filters.offset,
      },
    });

    const result: QueryResult = await pool.query(query);

    res.json({
      data: result.rows,
      meta: {
        limit: filters.limit,
        offset: filters.offset,
        count: result.rowCount,
      },
    });
  } catch (err: any) {
    console.error('Error in /admin/users:', err);

    if (err.message && err.message.startsWith('Invalid ')) {
      return res.status(400).json({ error: err.message });
    }

    res.status(500).json({ error: 'Internal server error' });
  }
});

// Global error handler
app.use((err: any, _req: Request, res: Response, _next: NextFunction) => {
  console.error('Unhandled error middleware:', err);
  res.status(500).json({ error: 'Internal server error' });
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Admin API running on port ${port} in ${process.env.NODE_ENV || 'development'} mode`);
});
```

**Defense in Depth Layers**:
1. **Controlled query builder + parameterization**:
   - All dynamic values go into `params` and are referenced as `$1`, `$2`, etc. The only string interpolation is for whitelisted identifiers:
   ```typescript
