For dynamic filters and sorting, avoid building SQL with string concatenation. Instead, use TypeORM's QueryBuilder with named parameters and strict whitelists for sortable/filtrable fields. Also, wrap this in production-grade controls like rate limiting, structured logging, and environment-specific configs.

**PRODUCTION PATTERN**:

```typescript
import "reflect-metadata";
import { DataSource, SelectQueryBuilder } from "typeorm";
import express, { Request, Response, NextFunction } from "express";
import helmet from "helmet";
import rateLimit from "express-rate-limit";
import validator from "validator";

class User {
  id!: number;
  email!: string;
  role!: string;
  createdAt!: Date;
}

const AppDataSource = new DataSource({
  type: "postgres",
  host: process.env.DB_HOST || "localhost",
  port: Number(process.env.DB_PORT || 5432),
  username: process.env.DB_USER || "app_user",
  password: process.env.DB_PASS || "secret",
  database: process.env.DB_NAME || "app_db",
  entities: [User],
  synchronize: false,
  logging: process.env.NODE_ENV === "production" ? ["error"] : ["query", "error"],
});

const app = express();
app.use(express.json());
app.use(helmet());

// Basic rate limiting for API abuse protection
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 200,
  standardHeaders: true,
  legacyHeaders: false,
});
app.use("/api/", apiLimiter);

// Simple request logging middleware
app.use((req: Request, _res: Response, next: NextFunction) => {
  console.log(`[${new Date().toISOString()}] ${req.method} ${req.originalUrl}`);
  next();
});

// Whitelists for safe dynamic sorting
const ALLOWED_SORT_FIELDS = ["email", "role", "createdAt"] as const;
type SortField = (typeof ALLOWED_SORT_FIELDS)[number];

const ALLOWED_SORT_DIRECTIONS = ["ASC", "DESC"] as const;
type SortDirection = (typeof ALLOWED_SORT_DIRECTIONS)[number];

app.get("/api/users", async (req: Request, res: Response) => {
  const email = (req.query.email as string | undefined) ?? undefined;
  const role = (req.query.role as string | undefined) ?? undefined;
  const createdFrom = (req.query.createdFrom as string | undefined) ?? undefined;
  const createdTo = (req.query.createdTo as string | undefined) ?? undefined;
  const page = Number(req.query.page || 1);
  const pageSize = Math.min(Number(req.query.pageSize || 20), 100);

  const sortFieldRaw = (req.query.sortField as string | undefined) ?? "createdAt";
  const sortDirRaw = ((req.query.sortDir as string | undefined) || "DESC").toUpperCase();

  // Validate and normalize filter input
  if (email && (!validator.isEmail(email) || email.length > 254)) {
    return res.status(400).json({ message: "Invalid email filter" });
  }

  if (role && role.length > 50) {
    return res.status(400).json({ message: "Invalid role filter" });
  }

  let createdFromDate: Date | undefined;
  let createdToDate: Date | undefined;
  if (createdFrom) {
    const d = new Date(createdFrom);
    if (isNaN(d.getTime())) {
      return res.status(400).json({ message: "Invalid createdFrom date" });
    }
    createdFromDate = d;
  }
  if (createdTo) {
    const d = new Date(createdTo);
    if (isNaN(d.getTime())) {
      return res.status(400).json({ message: "Invalid createdTo date" });
    }
    createdToDate = d;
  }

  // Whitelist sort field and direction
  const sortField: SortField = ALLOWED_SORT_FIELDS.includes(sortFieldRaw as SortField)
    ? (sortFieldRaw as SortField)
    : "createdAt";
  const sortDir: SortDirection = ALLOWED_SORT_DIRECTIONS.includes(sortDirRaw as SortDirection)
    ? (sortDirRaw as SortDirection)
    : "DESC";

  try {
    const repo = AppDataSource.getRepository(User);
    let qb: SelectQueryBuilder<User> = repo.createQueryBuilder("user");

    // Dynamic filters with named parameters (no string concatenation)
    if (email) {
      qb = qb.andWhere("user.email = :email", { email });
    }

    if (role) {
      qb = qb.andWhere("user.role = :role", { role });
    }

    if (createdFromDate) {
      qb = qb.andWhere("user.createdAt >= :createdFrom", { createdFrom: createdFromDate });
    }

    if (createdToDate) {
      qb = qb.andWhere("user.createdAt <= :createdTo", { createdTo: createdToDate });
    }

    // Safe sorting using whitelisted column names
    qb = qb.orderBy(`user.${sortField}`, sortDir);

    qb = qb.skip((page - 1) * pageSize).take(pageSize);

    const [users, total] = await qb.getManyAndCount();

    // Audit-style log (avoid sensitive data)
    console.log(
      JSON.stringify({
        event: "users_listed",
        at: new Date().toISOString(),
        filters: { email: !!email, role: !!role, createdFrom: !!createdFromDate, createdTo: !!createdToDate },
        pagination: { page, pageSize },
      })
    );

    return res.json({
      data: users.map((u) => ({ id: u.id, email: u.email, role: u.role, createdAt: u.createdAt })),
      meta: { total, page, pageSize },
    });
  } catch (err) {
    // Centralized error logging
    console.error("[GET /api/users] Unexpected error", err);
    return res.status(500).json({ message: "Internal server error" });
  }
});

// Generic error handler as last middleware
app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error("[GlobalError]", err);
  res.status(500).json({ message: "Unexpected error" });
});

AppDataSource.initialize()
  .then(() => {
    const port = Number(process.env.PORT || 3000);
    app.listen(port, () => {
      console.log(`API listening on port ${port} in ${process.env.NODE_ENV || "development"} mode`);
    });
  })
  .catch((err) => {
    console.error("Data source initialization failed", err);
    process.exit(1);
  });
```

**Defense in Depth Layers**:
1. **Safe dynamic querying with QueryBuilder**:
   - Uses named parameters instead of injecting values into SQL strings:
   ```typescript
   if (email) {
     qb = qb.andWhere("user.email = :email", { email });
   }
   ```
   - Prevents users from altering SQL structure even with malicious input.

2. **Strict whitelisting for sorting and filtering**:
   - Only allows predefined columns and directions, blocking injection via ORDER BY / column names:
   ```typescript
   const sortField: SortField = ALLOWED_SORT_FIELDS.includes(sortFieldRaw as SortField)
     ? (sortFieldRaw as SortField)
     : "createdAt";
   qb = qb.orderBy(`user.${sortField}`, sortDir);
   ```

3. **Validation, rate limiting, and error handling**:
   - Validates emails, dates, and sizes before touching the database.
   - Rate limits API usage to reduce brute-force and automated attacks.
   - Global error handler avoids leaking stack traces or SQL details to clients.

**Additional Protections**:
- **Environment-specific configuration**: Reads DB and logging options from environment variables and reduces logging verbosity in production to limit sensitive data exposure.
- **Security headers with Helmet**: Adds HTTP security headers (e.g., `X-Content-Type-Options`, `X-Frame-Options`) to mitigate other web attack vectors.
- **Audit logging and monitoring**: Structured logs for list operations (without sensitive data) facilitate anomaly detection and incident response when suspicious query patterns arise.

When using Prisma, it’s easy to assume everything is automatically safe. But as soon as you use `$queryRawUnsafe` or interpolate user input into raw SQL, you can reintroduce classic SQL injection vulnerabilities.

**VULNERABLE CODE**:

```typescript
import express, { Request, Response } from 'express';
import { PrismaClient } from '@prisma/client';

const app = express();
const prisma = new PrismaClient();

app.use(express.json());

// VULNERABLE: raw query with string interpolation from user input
app.get('/users/search', async (req: Request, res: Response) => {
  const search = (req.query.search as string) || '';
  const sort = (req.query.sort as string) || 'createdAt';

  try {
    const sql = `
      SELECT id, email, name
      FROM "User"
      WHERE email LIKE '%${search}%'
      ORDER BY ${sort} DESC
      LIMIT 20
    `;

    // Using $queryRawUnsafe with untrusted input
    const users = await prisma.$queryRawUnsafe(sql);

    res.json({ users });
  } catch (err: any) {
    // Leaks internal error details
    res.status(500).json({ error: err.message });
  }
});

app.listen(3000, () => {
  console.log('Server listening on port 3000');
});
```

**Attack Payload** (if applicable):
```sql
search=' OR '1'='1'--
```
This payload turns the `WHERE` clause into `WHERE email LIKE '%' OR '1'='1'--%'`, effectively returning all rows.

Another destructive payload targeting the `sort` parameter:
```sql
sort=id; DROP TABLE "User";--
```
If the database user is privileged enough, this can drop the entire `User` table.

**Why This Is Dangerous**:
- User-controlled input is concatenated directly into SQL strings, allowing arbitrary SQL execution.
- `$queryRawUnsafe` explicitly disables Prisma’s safety checks, so it will execute whatever SQL string you build.
- Lack of input validation and whitelisting (e.g., allowed sort columns) increases the impact of injection.

**SECURE VERSION**:

```typescript
import express, { Request, Response } from 'express';
import { PrismaClient } from '@prisma/client';

const app = express();
const prisma = new PrismaClient();

app.use(express.json());

// Define a whitelist of allowed sort fields
const ALLOWED_SORT_FIELDS = new Set(['createdAt', 'email', 'name']);

app.get('/users/search', async (req: Request, res: Response) => {
  const searchRaw = (req.query.search as string) || '';
  const sortRaw = (req.query.sort as string) || 'createdAt';

  // DEFENSE IN DEPTH: Input validation & normalization
  const search = searchRaw.trim().slice(0, 100); // limit length

  const sort = ALLOWED_SORT_FIELDS.has(sortRaw) ? sortRaw : 'createdAt';

  try {
    // PRIMARY DEFENSE: Use Prisma query builder instead of raw SQL
    const users = await prisma.user.findMany({
      where: {
        email: {
          contains: search,
          mode: 'insensitive'
        }
      },
      orderBy: {
        [sort]: 'desc'
      },
      take: 20
    });

    res.json({ users });
  } catch (err: any) {
    // SECURE ERROR HANDLING: Don't leak SQL details
    console.error('Database error in /users/search:', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.listen(3000, () => {
  console.log('Server listening on port 3000');
});
```

**Key Security Controls**:
- **Use Prisma’s typed query API instead of raw SQL**: `findMany` builds parameterized queries under the hood, so user data is never concatenated directly into SQL strings.
- **Input validation and whitelisting**: The `sort` field is checked against a fixed set of allowed columns; the `search` string is trimmed and length-limited to reduce abuse.
- **Secure error handling & logging**: Detailed errors are logged on the server, while the client only receives a generic message, preventing leakage of SQL or schema details.

For complex reporting or dynamic filters, you sometimes do need raw SQL with Prisma. In production, you must combine parameterized raw queries, strict whitelisting, environment-based safeguards, and strong observability.

**PRODUCTION PATTERN**:

```typescript
import express, { Request, Response, NextFunction } from 'express';
import rateLimit from 'express-rate-limit';
import helmet from 'helmet';
import { PrismaClient } from '@prisma/client';

const app = express();
const prisma = new PrismaClient();

app.use(express.json());
app.use(helmet());

// Simple environment-based config
