In production, you can safely build dynamic WHERE clauses by combining strict input validation with ORM-level parameter binding and structured logging/monitoring.

**PRODUCTION PATTERN**:

```typescript
import "reflect-metadata";
import { DataSource, Brackets } from "typeorm";
import express, { Request, Response, NextFunction } from "express";
import helmet from "helmet";

// Environment-aware configuration
const isProd = process.env.NODE_ENV === "production";

const AppDataSource = new DataSource({
    type: "postgres",
    host: process.env.DB_HOST || "localhost",
    port: Number(process.env.DB_PORT || 5432),
    username: process.env.DB_USER || "app_user",
    password: process.env.DB_PASS || "secret",
    database: process.env.DB_NAME || "app_db",
    logging: !isProd, // enable verbose SQL logging only in non-prod
});

const app = express();
app.use(express.json());
app.use(helmet());

// Simple in-memory rate limiting (example only, use a robust solution like Redis in prod)
const rateLimitWindowMs = 60_000;
const maxRequestsPerWindow = 60;
const ipHits: Record<string, { count: number; windowStart: number }> = {};

function rateLimiter(req: Request, res: Response, next: NextFunction) {
    const ip = req.ip || req.connection.remoteAddress || "unknown";
    const now = Date.now();
    const record = ipHits[ip] || { count: 0, windowStart: now };

    if (now - record.windowStart > rateLimitWindowMs) {
        record.count = 0;
        record.windowStart = now;
    }

    record.count++;
    ipHits[ip] = record;

    if (record.count > maxRequestsPerWindow) {
        console.warn(`[rate-limit] IP ${ip} exceeded limit`);
        return res.status(429).json({ error: "Too many requests" });
    }

    next();
}

app.use(rateLimiter);

// Utility: validate filters to avoid abuse and enforce types
function parseUserFilters(req: Request) {
    const email = (req.query.email as string) || undefined;
    const role = (req.query.role as string) || undefined;
    const createdFrom = (req.query.createdFrom as string) || undefined;
    const createdTo = (req.query.createdTo as string) || undefined;

    if (email && email.length > 200) {
        throw new Error("Invalid email filter");
    }

    const allowedRoles = ["admin", "user", "manager"];
    if (role && !allowedRoles.includes(role)) {
        throw new Error("Invalid role filter");
    }

    let createdFromDate: Date | undefined;
    let createdToDate: Date | undefined;

    if (createdFrom) {
        const d = new Date(createdFrom);
        if (Number.isNaN(d.getTime())) {
            throw new Error("Invalid createdFrom date");
        }
        createdFromDate = d;
    }

    if (createdTo) {
        const d = new Date(createdTo);
        if (Number.isNaN(d.getTime())) {
            throw new Error("Invalid createdTo date");
        }
        createdToDate = d;
    }

    return { email, role, createdFromDate, createdToDate };
}

app.get("/users/search", async (req: Request, res: Response) => {
    const requestId = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;

    try {
        const { email, role, createdFromDate, createdToDate } = parseUserFilters(req);

        const repo = AppDataSource.getRepository("users");
        const qb = repo
            .createQueryBuilder("u")
            .select(["u.id", "u.email", "u.role", "u.createdAt"])
            .limit(100);

        // Dynamic WHERE clauses with safe parameter binding
        if (email) {
            qb.andWhere("u.email ILIKE :email", { email: `%${email}%` });
        }

        if (role) {
            qb.andWhere("u.role = :role", { role });
        }

        if (createdFromDate || createdToDate) {
            qb.andWhere(
                new Brackets((subQb) => {
                    if (createdFromDate) {
                        subQb.andWhere("u.createdAt >= :createdFrom", { createdFrom: createdFromDate });
                    }
                    if (createdToDate) {
                        subQb.andWhere("u.createdAt <= :createdTo", { createdTo: createdToDate });
                    }
                })
            );
        }

        // Audit logging (without sensitive data)
        console.info("[users-search]", {
            requestId,
            emailFilter: !!email,
            roleFilter: role || null,
            createdFrom: createdFromDate ? createdFromDate.toISOString() : null,
            createdTo: createdToDate ? createdToDate.toISOString() : null,
            ip: req.ip,
        });

        const users = await qb.getMany();
        res.json({ requestId, users });
    } catch (err) {
        console.error("[users-search-error]", {
            requestId,
            message: (err as Error).message,
        });

        // Graceful degradation and generic errors
        if ((err as Error).message.startsWith("Invalid")) {
            return res.status(400).json({ error: "Invalid filter input" });
        }

        res.status(500).json({ error: "Internal server error" });
    }
});

